 1→import * as vscode from "vscode";
 2→import { execSync } from "child_process";
 3→
 4→interface KohSession {
 5→  name: string;
 6→  attached: boolean;
 7→  created: string;
 8→}
 9→
10→function listKohSessions(): KohSession[] {
11→  try {
12→    const output = execSync(
13→      'tmux list-sessions -F "#{session_name}|#{session_attached}|#{session_created}" 2>/dev/null',
14→      { encoding: "utf-8" }
15→    );
16→
17→    return output
18→      .trim()
19→      .split("\n")
20→      .filter((line) => line.startsWith("koh-"))
21→      .map((line) => {
22→        const [name, attached, created] = line.split("|");
23→        return {
24→          name,
25→          attached: attached === "1",
26→          created: new Date(parseInt(created) * 1000).toLocaleString(),
27→        };
28→      });
29→  } catch {
30→    return [];
31→  }
32→}
33→
34→function attachToSession(sessionName: string) {
35→  const terminal = vscode.window.createTerminal({
36→    name: sessionName,
37→    shellPath: process.env.SHELL,
38→    shellArgs: ["-c", `tmux attach-session -t "${sessionName}"`],
39→    location: vscode.TerminalLocation.Editor,
40→  });
41→  terminal.show();
42→}
43→
44→export function activate(context: vscode.ExtensionContext) {
45→  // Track known sessions to detect new ones
46→  let knownSessions = new Set(listKohSessions().map((s) => s.name));
47→
48→  // Poll for new koh tmux sessions every 2 seconds
49→  const watcher = setInterval(() => {
50→    const current = listKohSessions();
51→    for (const session of current) {
52→      if (!knownSessions.has(session.name) && !session.attached) {
53→        knownSessions.add(session.name);
54→        attachToSession(session.name);
55→      }
56→    }
57→    // Update known set (remove gone sessions)
58→    knownSessions = new Set(current.map((s) => s.name));
59→  }, 2000);
60→
61→  context.subscriptions.push({ dispose: () => clearInterval(watcher) });
62→
63→  // Manual attach command
64→  const attach = vscode.commands.registerCommand("koh.attach", async () => {
65→    const sessions = listKohSessions();
66→
67→    if (sessions.length === 0) {
68→      vscode.window.showInformationMessage("No koh sessions running.");
69→      return;
70→    }
71→
72→    const items = sessions.map((s) => ({
73→      label: s.name,
74→      description: s.attached ? "attached" : "",
75→      detail: `Created: ${s.created}`,
76→    }));
77→
78→    const pick = await vscode.window.showQuickPick(items, {
79→      placeHolder: "Select a koh session to attach",
80→    });
81→
82→    if (!pick) {
83→      return;
84→    }
85→
86→    attachToSession(pick.label);
87→  });
88→
89→  context.subscriptions.push(attach);
90→}
91→
92→export function deactivate() {}
